```class Solution {
    public String discountPrices(String sentence, int discount) {
        String[] words = sentence.split(" ");
        for (int i = 0; i < words.length; i++) {
            if (words[i].startsWith("$") && words[i].length() > 1 && words[i].charAt(1) >= '0' && words[i].charAt(1) <= '9') {
                double price = Double.parseDouble(words[i].substring(1));
                double discountedPrice = price * (1 - discount / 100.0);
                words[i] = String.format("$%.2f", discountedPrice);
            }
        }
        return String.join(" ", words);
    }
}```
